import{_ as a,c as t,o as e,a1 as i}from"./chunks/framework.TuIRSVI8.js";const f=JSON.parse('{"title":"Platform Support","description":"","frontmatter":{"title":"Platform Support"},"headers":[],"relativePath":"versions/index.md","filePath":"versions/index.md","lastUpdated":1768004173000}'),n={name:"versions/index.md"};function o(l,s,p,r,d,c){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="platform-support" tabindex="-1">Platform Support <a class="header-anchor" href="#platform-support" aria-label="Permalink to &quot;Platform Support&quot;">​</a></h1><p>All platforms use a <strong>single <code>main</code> branch</strong>. Platform-specific files are excluded at deploy time via <code>.chezmoiignore.tmpl</code>.</p><h2 id="supported-platforms" tabindex="-1">Supported Platforms <a class="header-anchor" href="#supported-platforms" aria-label="Permalink to &quot;Supported Platforms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>Full support</td><td>Homebrew, Alfred workflows, TouchID/1Password</td></tr><tr><td><strong>Linux</strong> (Ubuntu/Fedora/Arch)</td><td>Full support</td><td>apt/dnf packages, systemd integration</td></tr><tr><td><strong>WSL</strong></td><td>Full support</td><td>Windows 1Password integration, symlinked paths</td></tr><tr><td><strong>Bazzite / Steam Deck</strong></td><td>Full support</td><td>Immutable OS tweaks, Deck UI, Proton paths</td></tr></tbody></table><h2 id="how-platform-detection-works" tabindex="-1">How Platform Detection Works <a class="header-anchor" href="#how-platform-detection-works" aria-label="Permalink to &quot;How Platform Detection Works&quot;">​</a></h2><p>chezmoi uses <code>.chezmoiignore.tmpl</code> to exclude files based on the host system:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Example exclusions (simplified)</span></span>
<span class="line"><span>{{- if ne .chezmoi.os &quot;darwin&quot; }}</span></span>
<span class="line"><span># Linux: Exclude macOS-specific files</span></span>
<span class="line"><span>private_dot_config/alfred/</span></span>
<span class="line"><span>{{- end }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{- if ne .chezmoi.os &quot;linux&quot; }}</span></span>
<span class="line"><span># macOS: Exclude Linux-specific files</span></span>
<span class="line"><span>private_dot_config/systemd/</span></span>
<span class="line"><span>private_dot_config/sunshine/</span></span>
<span class="line"><span>{{- end }}</span></span></code></pre></div><h2 id="installation-all-platforms" tabindex="-1">Installation (All Platforms) <a class="header-anchor" href="#installation-all-platforms" aria-label="Permalink to &quot;Installation (All Platforms)&quot;">​</a></h2><p>The same command works everywhere:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsLS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get.chezmoi.io)&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aristoddle/beppe-system-bootstrap</span></span></code></pre></div><p>After install, run <code>dotfiles doctor</code> to verify platform-specific tools are available.</p><h2 id="platform-specific-docs" tabindex="-1">Platform-Specific Docs <a class="header-anchor" href="#platform-specific-docs" aria-label="Permalink to &quot;Platform-Specific Docs&quot;">​</a></h2><ul><li><a href="/beppe-dotfiles-docs/USING_BAZZITE">Using Bazzite</a> - Steam Deck / HTPC running Bazzite</li><li><a href="/beppe-dotfiles-docs/PLATFORM_DIFFERENCES">Platform Differences</a> - Tool availability across platforms</li><li><a href="/beppe-dotfiles-docs/RECOVERY_QUICK_REFERENCE">Recovery Quick Reference</a> - Platform-specific recovery steps</li></ul>`,13)])])}co